#include <bits/stdc++.h>
using namespace std;

const int N=5010;

struct Node{
	int v,w;
}b[N];

bool cmp(Node a,Node b){
	if(1ll*a.v*b.w==1ll*b.v*a.w)
		return a.w>b.w;
	return 1ll*a.v*b.w>1ll*b.v*a.w;
}

int c,T,n,m,a[N],f[N][N];

int main(){
	scanf("%d%d",&c,&T);
	while(T--){
		scanf("%d%d",&n,&m);
		for(int i=1;i<=n;i++)
			scanf("%d",&a[i]);
		int ans=0;
		for(int i=0;i<1<<n;i++){
			for(int j=1;j<=n;j++){
				b[j].v=a[j];
				b[j].w=1+((i>>j-1)&1);
			}
			sort(b+1,b+n+1,cmp);
			int cnt=0,lst1=-1,lst2=-1;
			bool flag=1;
			b[n+1].v=0;
			b[n+1].w=1;
			for(int j=1;j<=n+1;j++){
				//printf("%d/%d(%d,%d) ",b[j].v,b[j].w,lst1,lst2);
				if(cnt+b[j].w<=m){
					cnt+=b[j].w;
					if(cnt==m && b[j].w==1){
						if(lst1!=-1 && lst2!=-1 && b[lst2].v>b[lst1].v+b[j].v){
							flag=0;
							break;
						}
					}
					if(b[j].w==1)
						lst1=j;
				}else if(lst2==-1 && b[j].w==2)
					lst2=j;
			}
			if(flag)
				ans++;
			//puts("");
		}
		printf("%d\n",ans);
	}
	return 0;
}
